{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyNJwi8H8U/yjPdyts0+kDcd"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"mViQeFGfZ1-S","executionInfo":{"status":"ok","timestamp":1775287947752,"user_tz":-330,"elapsed":7017,"user":{"displayName":"Ritwik Singh","userId":"13031647467658187950"}},"outputId":"8ceef074-95ac-4ba1-a592-b91bf93d840f"},"outputs":[{"output_type":"stream","name":"stdout","text":["Requirement already satisfied: requests in /usr/local/lib/python3.12/dist-packages (2.32.4)\n","Requirement already satisfied: charset_normalizer<4,>=2 in /usr/local/lib/python3.12/dist-packages (from requests) (3.4.6)\n","Requirement already satisfied: idna<4,>=2.5 in /usr/local/lib/python3.12/dist-packages (from requests) (3.11)\n","Requirement already satisfied: urllib3<3,>=1.21.1 in /usr/local/lib/python3.12/dist-packages (from requests) (2.5.0)\n","Requirement already satisfied: certifi>=2017.4.17 in /usr/local/lib/python3.12/dist-packages (from requests) (2026.2.25)\n"]}],"source":["!pip install requests"]},{"cell_type":"code","source":["import requests #for making api\n","\n","import json\n","import time\n","import os\n","from datetime import datetime\n","\n","# Function to categorize stories based on keywords in the title\n","def assign_category(title):\n","    title = title.lower()\n","    if 'ai' in title or 'ml' in title or 'intelligence' in title:\n","        return 'AI/ML'\n","    elif 'show hn' in title:\n","        return 'Showcase'\n","    elif 'python' in title or 'rust' in title or 'coding' in title:\n","        return 'Programming'\n","    elif 'startup' in title or 'business' in title:\n","        return 'Business'\n","    else:\n","        return 'General Tech'\n","\n","def run_scraper():\n","    # 1. Setup: Create data directory\n","    folder = 'data'\n","    if not os.path.exists(folder):\n","        os.makedirs(folder)\n","        print(f\"Created directory: {folder}\")\n","\n","    # 2. Fetch Story IDs\n","    top_stories_url = \"https://hacker-news.firebaseio.com/v0/topstories.json\"\n","    try:\n","        response = requests.get(top_stories_url)\n","        response.raise_for_status()\n","        # We need 125 stories (25 per category loop)\n","        all_ids = response.json()[:125]\n","    except Exception as e:\n","        print(f\"Initial API call failed: {e}\")\n","        return\n","\n","    extracted_data = []\n","\n","    # 3. Process Stories in batches of 25\n","    for index, post_id in enumerate(all_ids):\n","        try:\n","            item_url = f\"https://hacker-news.firebaseio.com/v0/item/{post_id}.json\"\n","            item_res = requests.get(item_url)\n","            item_res.raise_for_status()\n","            story = item_res.json()\n","\n","            # Ensure the item is actually a story (some IDs might be jobs or polls)\n","            if story.get('type') != 'story':\n","                continue\n","\n","            # Extract specific fields required by the task\n","            record = {\n","                \"post_id\": story.get(\"id\"),\n","                \"title\": story.get(\"title\", \"No Title\"),\n","                \"category\": assign_category(story.get(\"title\", \"\")),\n","                \"score\": story.get(\"score\", 0),\n","                \"num_comments\": story.get(\"descendants\", 0), # 'descendants' is the API field\n","                \"author\": story.get(\"by\", \"unknown\"),\n","                \"collected_at\": datetime.now().strftime(\"%Y-%m-%d %H:%M:%S\")\n","            }\n","\n","            extracted_data.append(record)\n","\n","            # Throttling requirement: 2s sleep per 'category' (every 25 items)\n","            if (index + 1) % 25 == 0:\n","                print(f\"Processed {index + 1} items. Pausing for 2 seconds...\")\n","                time.sleep(2)\n","\n","        except Exception as err:\n","            print(f\"Skipping story {post_id} due to error: {err}\")\n","            continue\n","\n","    # 4. Save to JSON\n","    date_str = datetime.now().strftime(\"%Y%m%d\")\n","    filename = f\"{folder}/trends_{date_str}.json\"\n","\n","    with open(filename, 'w', encoding='utf-8') as f:\n","        json.dump(extracted_data, f, indent=4)\n","\n","    print(\"-\" * 30)\n","    print(f\"Success! Collected {len(extracted_data)} stories.\")\n","    print(f\"File saved at: {filename}\")\n","\n","if __name__ == \"__main__\":\n","    run_scraper()"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"geELjI7fgqKQ","executionInfo":{"status":"ok","timestamp":1775464768513,"user_tz":-330,"elapsed":21967,"user":{"displayName":"Ritwik Singh","userId":"13031647467658187950"}},"outputId":"9b559b7b-5310-4121-fad1-d9dc8d07856e"},"execution_count":1,"outputs":[{"output_type":"stream","name":"stdout","text":["Created directory: data\n","Processed 25 items. Pausing for 2 seconds...\n","Processed 50 items. Pausing for 2 seconds...\n","Processed 75 items. Pausing for 2 seconds...\n","Processed 100 items. Pausing for 2 seconds...\n","Processed 125 items. Pausing for 2 seconds...\n","------------------------------\n","Success! Collected 124 stories.\n","File saved at: data/trends_20260406.json\n"]}]},{"cell_type":"code","source":[],"metadata":{"id":"EHhxgMWw6_WP"},"execution_count":null,"outputs":[]},{"cell_type":"code","source":[],"metadata":{"id":"FJmN3A6H6_v0"},"execution_count":null,"outputs":[]}]}